import math

def solve(series_list: list[str]) -> float:
    def parse_series(series_str: str) -> dict[str, Any]:
        parts = series_str.split("|")
        if len(parts) != 2:
            raise ValueError("Invalid Nimbla series format")
        timestamps = list(map(int, parts[0].split(",")))
        values = list(map(float, parts[1].split(",")))
        return {"timestamps": timestamps, "values": values}

    def merge_series(series1: dict[str, Any], series2: dict[str, Any]) -> dict[str, Any]:
        timestamps1 = series1["timestamps"]
        values1 = series1["values"]
        timestamps2 = series2["timestamps"]
        values2 = series2["values"]

        # Find the intersection of timestamps
        common_timestamps = set(timestamps1) & set(timestamps2)

        # Merge values based on common timestamps
        merged_values = [values1[timestamps1.index(ts)] if ts in timestamps1 else values2[timestamps2.index(ts)] for ts in common_timestamps]

        return {"timestamps": list(common_timestamps), "values": merged_values}

    def normalize(series: dict[str, Any], method: str = "minmax") -> list[float]:
        values = series["values"]
        if not values:
            return []
        if method == "minmax":
            min_v = min(values)
            max_v = max(values)
            if max_v == min_v:
                return [0.0] * len(values)
            return [(v - min_v) / (max_v - min_v) for v in values]
        if method == "zscore":
            mean = sum(values) / len(values)
            std = math.sqrt(sum((v - mean) ** 2 for v in values) / len(values))
            if std == 0:
                return [0.0] * len(values)
            return [(v - mean) / std for v in values]
        raise ValueError(f"Unsupported normalization method: {method}")

    def average_normalized(series: list[float]) -> float:
        if not series:
            return 0.0
        return sum(series) / len(series)

    # Parse each series
    parsed_series = [parse_series(series_str) for series_str in series_list]

    # Merge all series
    merged_series = parsed_series[0]
    for series in parsed_series[1:]:
        merged_series = merge_series(merged_series, series)

    # Normalize the merged series
    normalized_series = normalize(merged_series, method="minmax")

    # Calculate the average of the normalized series
    average_value = average_normalized(normalized_series)

    return average_value
