            return values[-1]
        if method == "mean":
            return sum(values) / len(values)
        if method == "diff":
            if len(values) == 1:
                return values[-1]
            diffs = [values[i] - values[i - 1] for i in range(1, len(values))]
            return values[-1] + (sum(diffs) / len(diffs))
        raise ValueError(f"Unsupported forecast method: {method}")

    def mean_forecast(series: dict[str, Any]) -> float:
        return forecast_next(series, method="mean")

    def diff_forecast(series: dict[str, Any]) -> float:
        return forecast_next(series, method="diff")

